package main

import ( "fmt"; "time" )

func slowOperation() <-chan string {
	ch := make(chan string, 1)
	go func() { time.Sleep(200 * time.Millisecond); ch <- "slow result" }()
	return ch
}

func main() {
	result := slowOperation()
	select {
	case v := <-result:
		fmt.Println("got:", v)
	case <-time.After(50 * time.Millisecond):
		fmt.Println("timeout: operation took too long")
	}
}

package main

import ( "fmt"; "time" )

func counter(done <-chan struct{}) {
	for i := 1; ; i++ {
		select {
		case <-done:
			fmt.Println("counter stopped at", i-1)
			return
		default:
			fmt.Println("count:", i)
			time.Sleep(30 * time.Millisecond)
		}
	}
}

func main() {
	done := make(chan struct{})
	go counter(done)
	time.Sleep(100 * time.Millisecond)
	close(done)
	time.Sleep(50 * time.Millisecond)
	fmt.Println("main done")
}

package main

import ( "fmt"; "sync" )

func merge(ch1, ch2 <-chan int) <-chan int {
	out := make(chan int)
	var wg sync.WaitGroup
	forward := func(ch <-chan int) {
		defer wg.Done()
		for v := range ch { out <- v }
	}
	wg.Add(2)
	go forward(ch1)
	go forward(ch2)
	go func() { wg.Wait(); close(out) }()
	return out
}

func source(vals ...int) <-chan int {
	ch := make(chan int, len(vals))
	for _, v := range vals { ch <- v }
	close(ch)
	return ch
}

func main() {
	ch1 := source(1,2,3)
	ch2 := source(4,5,6)
	merged := merge(ch1, ch2)
	total := 0
	for v := range merged { fmt.Println("received:", v); total += v }
	fmt.Println("total:", total)
}
